func solve(nums []int64, queries [][]int64) int64 {
    MOD := 1000000007
    n := len(nums)
    factors := make([]int64, n)
    for i := range factors {
        factors[i] = 1
    }
    for _, q := range queries {
        li := q[0]
        ri := q[1]
        ki := q[2]
        vi := q[3]
        current := li
        for current <= ri {
            factors[current] = (factors[current] * vi) % MOD
            current += ki
        }
    }
    result := int64(0)
    for i := 0; i < n; i++ {
        val := (nums[i] * factors[i]) % MOD
        result ^= val
    }
    return result
}
